1451	    function createToken<TKind extends KeywordSyntaxKind>(token: TKind): KeywordToken<TKind>;
1452	    function createToken<TKind extends SyntaxKind>(token: TKind): Token<TKind>;
1453	    function createToken<TKind extends SyntaxKind>(token: TKind) {
1454	        Debug.assert(token >= SyntaxKind.FirstToken && token <= SyntaxKind.LastToken, "Invalid token");
1455	        Debug.assert(token <= SyntaxKind.FirstTemplateToken || token >= SyntaxKind.LastTemplateToken, "Invalid token. Use 'createTemplateLiteralLikeNode' to create template literals.");
1456	        Debug.assert(token <= SyntaxKind.FirstLiteralToken || token >= SyntaxKind.LastLiteralToken, "Invalid token. Use 'createLiteralLikeNode' to create literals.");
1457	        Debug.assert(token !== SyntaxKind.Identifier, "Invalid token. Use 'createIdentifier' to create identifiers");
1458	        const node = createBaseToken<Token<TKind>>(token);
1459	        let transformFlags = TransformFlags.None;
1460	        switch (token) {
1461	            case SyntaxKind.AsyncKeyword:
1462	                // 'async' modifier is ES2017 (async functions) or ES2018 (async generators)
1463	                transformFlags = TransformFlags.ContainsES2017 |
1464	                    TransformFlags.ContainsES2018;
1465	                break;
1466	
1467	            case SyntaxKind.UsingKeyword:
1468	                transformFlags = TransformFlags.ContainsESNext;
1469	                break;
1470	
1471	            case SyntaxKind.PublicKeyword:
1472	            case SyntaxKind.PrivateKeyword:
1473	            case SyntaxKind.ProtectedKeyword:
1474	            case SyntaxKind.ReadonlyKeyword:
1475	            case SyntaxKind.AbstractKeyword:
1476	            case SyntaxKind.DeclareKeyword:
1477	            case SyntaxKind.ConstKeyword:
1478	            case SyntaxKind.AnyKeyword:
1479	            case SyntaxKind.NumberKeyword:
1480	            case SyntaxKind.BigIntKeyword:
1481	            case SyntaxKind.NeverKeyword:
1482	            case SyntaxKind.ObjectKeyword:
1483	            case SyntaxKind.InKeyword:
1484	            case SyntaxKind.OutKeyword:
1485	            case SyntaxKind.OverrideKeyword:
1486	            case SyntaxKind.StringKeyword:
1487	            case SyntaxKind.BooleanKeyword:
1488	            case SyntaxKind.SymbolKeyword:
1489	            case SyntaxKind.VoidKeyword:
1490	            case SyntaxKind.UnknownKeyword:
1491	            case SyntaxKind.UndefinedKeyword: // `undefined` is an Identifier in the expression case.
1492	                transformFlags = TransformFlags.ContainsTypeScript;
1493	                break;
1494	            case SyntaxKind.SuperKeyword:
1495	                transformFlags = TransformFlags.ContainsES2015 | TransformFlags.ContainsLexicalSuper;
1496	                (node as Mutable<Token<SyntaxKind.SuperKeyword>> as Mutable<SuperExpression>).flowNode = undefined; // initialized by binder (FlowContainer)
1497	                break;
1498	            case SyntaxKind.StaticKeyword:
1499	                transformFlags = TransformFlags.ContainsES2015;
1500	                break;
1501	            case SyntaxKind.AccessorKeyword:
1502	                transformFlags = TransformFlags.ContainsClassFields;
1503	                break;
1504	            case SyntaxKind.ThisKeyword:
