1564	        if (flags & ModifierFlags.Abstract) result.push(createModifier(SyntaxKind.AbstractKeyword));
1565	        if (flags & ModifierFlags.Static) result.push(createModifier(SyntaxKind.StaticKeyword));
1566	        if (flags & ModifierFlags.Override) result.push(createModifier(SyntaxKind.OverrideKeyword));
