6381	        }
6382	        if (isIdentifier(node)) {
6383	            return cloneIdentifier(node) as T & Identifier;
6384	        }
6385	        if (isGeneratedPrivateIdentifier(node)) {
6386	            return cloneGeneratedPrivateIdentifier(node) as T & GeneratedPrivateIdentifier;
6387	        }
6388	        if (isPrivateIdentifier(node)) {
6389	            return clonePrivateIdentifier(node) as T & PrivateIdentifier;
6390	        }
6391	
6392	        const clone = !isNodeKind(node.kind) ? baseFactory.createBaseTokenNode(node.kind) as T :
6393	            baseFactory.createBaseNode(node.kind) as T;
6394	
6395	        (clone as Mutable<T>).flags |= node.flags & ~NodeFlags.Synthesized;
6396	        (clone as Mutable<T>).transformFlags = node.transformFlags;
